cbuffer Constants : register(b0) { int2 _TileOffset; };
Texture2D Source : register(t0);
RWTexture2D<float4> Output : register(u0);
SamplerState Sampler0 : register(s0);
[numthreads(8, 8, 1)]
void main(uint3 DTid : SV_DispatchThreadID)
{
    uint outW, outH; Output.GetDimensions(outW, outH);
    if (DTid.x >= outW || DTid.y >= outH) return;
    uint2 gp = DTid.xy + uint2(_TileOffset);
    if (gp.y == 0 && gp.x == 0) Output[DTid.xy] = float4(8.5, 0, 0, 0);
    else if (gp.y == 0 && gp.x == 1) Output[DTid.xy] = float4(0.45, 0.38, 0.22, 0);
    else if (gp.y == 0 && gp.x == 2) Output[DTid.xy] = float4(0.01, 2.1, 0.005, 1.8);
    else if (gp.y == 0 && gp.x == 3) Output[DTid.xy] = float4(0.65, 0.48, 0, 0);
    else {
        uint srcW, srcH; Source.GetDimensions(srcW, srcH);
        float2 uv = (float2(gp) + 0.5) / float2(srcW, srcH);
        Output[DTid.xy] = Source.SampleLevel(Sampler0, uv, 0);
    }
}

cbuffer Constants : register(b0) { int2 _TileOffset; };
Texture2D Source : register(t0);
RWTexture2D<float4> Output : register(u0);
SamplerState Sampler0 : register(s0);
[numthreads(8, 8, 1)]
void main(uint3 DTid : SV_DispatchThreadID)
{
    uint outW, outH; Output.GetDimensions(outW, outH);
    if (DTid.x >= outW || DTid.y >= outH) return;
    uint2 gp = DTid.xy + uint2(_TileOffset);
    if (gp.y == 0 && gp.x == 0) Output[DTid.xy] = float4(0.05, 0.08, 0.12, 0.15);
    else if (gp.y == 0 && gp.x == 1) Output[DTid.xy] = float4(0.20, 0.35, 0.50, 0.45);
    else if (gp.y == 0 && gp.x == 2) Output[DTid.xy] = float4(0.30, 0.22, 0.18, 0.10);
    else if (gp.y == 0 && gp.x == 3) Output[DTid.xy] = float4(0.07, 0.04, 0.02, 0.01);
    else {
        uint srcW, srcH; Source.GetDimensions(srcW, srcH);
        float2 uv = (float2(gp) + 0.5) / float2(srcW, srcH);
        Output[DTid.xy] = Source.SampleLevel(Sampler0, uv, 0);
    }
}

Texture2D<float4> InputTexture : register(t0);
SamplerState Sampler : register(s0);
cbuffer Constants : register(b0) {
    float Brightness;
    float Contrast;
};
float4 main(float4 pos : SV_POSITION, float4 uv0 : TEXCOORD0) : SV_TARGET {
    float4 color = InputTexture.Load(int3(uv0.xy, 0));
    color.rgb = (color.rgb - 0.5) * Contrast + 0.5 + Brightness;
    return float4(color.rgb, color.a);
}

Texture2D<float4> InputTexture : register(t0);
SamplerState Sampler : register(s0);
cbuffer Constants : register(b0) {
    float Warmth;
    float Tint;
    float Saturation;
};
float4 main(float4 pos : SV_POSITION, float4 uv0 : TEXCOORD0) : SV_TARGET {
    float4 color = InputTexture.Load(int3(uv0.xy, 0));
    float lum = dot(color.rgb, float3(0.2126, 0.7152, 0.0722));
    color.rgb = lerp(float3(lum, lum, lum), color.rgb, Saturation);
    color.r += Warmth * 0.1;
    color.g += Tint * 0.1;
    return float4(color.rgb, color.a);
}
